import face_recognition
from flask import Flask, request, jsonify
from sklearn.model_selection import train_test_split
from sklearn.preprocessing import StandardScaler
from sklearn.svm import SVC
from sklearn.metrics import accuracy_score
from PIL import Image
import numpy as np
import os

app = Flask(__name__)

# Load employee photos and extract face encodings
employee_photos = []
for file in os.listdir('employee_photos'):
    image = face_recognition.load_image_file(os.path.join('employee_photos', file))
    encoding = face_recognition.face_encodings(image)[0]
    employee_photos.append(encoding)

# Train model on employee photos
X_train, X_test, y_train, y_test = train_test_split(employee_photos, [i for i in range(len(employee_photos))], test_size=0.2)
scaler = StandardScaler()
X_train_scaled = scaler.fit_transform(X_train)
model = SVC(kernel='rbf', probability=True)
model.fit(X_train_scaled, y_train)

# Prevent model inversion
def prevent_inversion(image):
    image = face_recognition.load_image_file(image)
    encoding = face_recognition.face_encodings(image)[0]
    return np.random.rand(128)  # Return a random vector instead of the actual encoding

@app.route('/recognize', methods=['POST'])
def recognize():
    image = request.files['image']
    encoding = prevent_inversion(image)
    scaled_encoding = scaler.transform([encoding])
    prediction = model.predict(scaled_encoding)
    confidence = model.decision_function(scaled_encoding)
    probabilities = model.predict_proba(scaled_encoding)
    return jsonify({
        'prediction': int(prediction[0]),
        'confidence': float(confidence[0]),
        'probabilities': [float(p) for p in probabilities[0]]
    })

if __name__ == '__main__':
    app.run(debug=True)